        "import ipywidgets as widgets\n",
        "from IPython.display import display, clear_output, HTML\n",
        "import folium\n",
        "import requests\n",
        "import polyline\n",
        "from datetime import datetime\n",
        "\n",
        "# --- 1. GIAO DIỆN ---\n",
        "style = {'description_width': 'initial'}\n",
        "header = widgets.HTML(\"<h2>🚖 App Đặt Xe Thông Minh v2 (Fix Map)</h2>\")\n",
        "\n",
        "start_address = widgets.Text(value='Bệnh viện Bình Dân', description='Điểm đi:', style=style)\n",
        "end_address = widgets.Text(value='Chợ Bến Thành', description='Điểm đến:', style=style)\n",
        "\n",
        "car_type = widgets.Dropdown(\n",
        "    options=[\n",
        "        ('Xe máy Điện (Tiết kiệm)', 'dien'),\n",
        "        ('Xe máy Xăng cũ (Tiết kiệm)', 'cu'),\n",
        "        ('Xe Standard (Cơ bản)', 'standard'),\n",
        "        ('Xe Premium (Priority)', 'premium')\n",
        "    ],\n",
        "    value='standard', description='Loại phương tiện:', style=style\n",
        ")\n",
        "\n",
        "env_fee = widgets.Checkbox(value=False, description='Phí môi trường (1,000đ)')\n",
        "ride_cover = widgets.Checkbox(value=False, description='Ride Cover (Bảo hiểm)')\n",
        "\n",
        "btn_calculate = widgets.Button(description='TÌM ĐƯỜNG & TÍNH PHÍ', button_style='success', layout={'width': '300px'})\n",
        "output_area = widgets.Output()\n",
        "\n",
        "# --- 2. HÀM HỖ TRỢ ---\n",
        "def get_coords(address):\n",
        "    try:\n",
        "        url = \"https://nominatim.openstreetmap.org/search?format=json&q=\" + address\n",
        "        headers = {'User-Agent': 'MyRideApp/1.0'}\n",
        "        res = requests.get(url, headers=headers).json()\n",
        "        if res:\n",
        "            return float(res[0]['lat']), float(res[0]['lon'])\n",
        "    except:\n",
        "        return None\n",
        "    return None\n",
        "\n",
        "def get_weather_multiplier(lat, lon):\n",
        "    try:\n",
        "        url = \"https://api.open-meteo.com/v1/forecast?latitude=\" + str(lat) + \"&longitude=\" + str(lon) + \"&current_weather=true\"\n",
        "        res = requests.get(url).json()\n",
        "        code = res['current_weather']['weathercode']\n",
        "        # Các code mưa: 51, 53, 55, 61, 63, 65, 80, 81, 82\n",
        "        if code in [51, 53, 55, 61, 63, 65, 80, 81, 82]:\n",
        "            return 1.2, \"Đang có mưa (Phí thời tiết x1.2)\"\n",
        "    except:\n",
        "        return 1.0, \"Không lấy được dữ liệu thời tiết\"\n",
        "    return 1.0, \"Thời tiết đẹp\"\n",
        "\n",
        "# --- 3. LOGIC CHÍNH ---\n",
        "def handle_click(b):\n",
        "    with output_area:\n",
        "        clear_output()\n",
        "        print(\"Đang xử lý dữ liệu... Vui lòng chờ vài giây.\")\n",
        "\n",
        "        start_loc = get_coords(start_address.value)\n",
        "        end_loc = get_coords(end_address.value)\n",
        "\n",
        "        if not start_loc or not end_loc:\n",
        "            print(\"❌ Lỗi: Không tìm thấy địa chỉ. Hãy thử nhập tên đường hoặc quận cụ thể hơn!\")\n",
        "            return\n",
        "\n",
        "        # Tính quãng đường (OSRM)\n",
        "        url_route = \"http://router.project-osrm.org/route/v1/driving/\" + str(start_loc[1]) + \",\" + str(start_loc[0]) + \";\" + str(end_loc[1]) + \",\" + str(end_loc[0]) + \"?overview=full\"\n",
        "        route_res = requests.get(url_route).json()\n",
        "\n",
        "        if 'routes' not in route_res or len(route_res['routes']) == 0:\n",
        "            print(\"❌ Lỗi: Không thể tìm đường đi giữa hai điểm này.\")\n",
        "            return\n",
        "\n",
        "        route = route_res['routes'][0]\n",
        "        dist_km = route['distance'] / 1000\n",
        "        duration = route['duration'] / 60\n",
        "\n",
        "        w_mult, w_text = get_weather_multiplier(start_loc[0], start_loc[1])\n",
        "\n",
        "        hour = datetime.now().hour\n",
        "        rush_mult = 1.0\n",
        "        if (7 <= hour <= 9) or (16 <= hour <= 19):\n",
        "            rush_mult = 1.5\n",
        "\n",
        "        prices = {'dien': 5000, 'cu': 6000, 'standard': 8000, 'premium': 15000}\n",
        "        base_price = dist_km * prices[car_type.value]\n",
        "\n",
        "        final_price = base_price * w_mult * rush_mult\n",
        "\n",
        "        if env_fee.value: final_price += 1000\n",
        "        if ride_cover.value:\n",
        "            final_price += 4000 if dist_km > 5 else 2000\n",
        "\n",
        "        print(\"📍 Quãng đường: \" + \"{:.2f}\".format(dist_km) + \" km\")\n",
        "        print(\"⏰ Thời gian dự kiến: \" + \"{:.0f}\".format(duration) + \" phút\")\n",
        "        print(\"☀️ \" + w_text)\n",
        "        if rush_mult > 1: print(\"🔥 Giờ cao điểm (x1.5)\")\n",
        "        print(\"💰 TỔNG CỘNG: \" + \"{:,.0f}\".format(final_price) + \" VNĐ\")\n",
        "\n",
        "        # --- PHẦN FIX MAP: Xuất ra HTML ---\n",
        "        m = folium.Map(location=start_loc, zoom_start=14)\n",
        "        folium.Marker(start_loc, popup=\"Điểm đi\", icon=folium.Icon(color='green')).add_to(m)\n",
        "        folium.Marker(end_loc, popup=\"Điểm đến\", icon=folium.Icon(color='red')).add_to(m)\n",
        "        points = polyline.decode(route['geometry'])\n",
        "        folium.PolyLine(points, color=\"blue\", weight=5).add_to(m)\n",
        "\n",
        "        # Chuyển bản đồ sang dạng HTML để hiển thị trong Colab\n",
        "        display(HTML(m._repr_html_()))\n",
        "\n",
        "btn_calculate.on_click(handle_click)\n",
        "\n",
        "# Hiển thị app\n",
        "display(header, start_address, end_address, car_type, env_fee, ride_cover, btn_calculate, output_area)"
